"}$json$::jsonb, $json$["fast delivery speed","responsive support","strong HelloPeter ratings","innovative tech (Sixty60)","local partnerships"]$json$::jsonb, $json$["surge pricing","app reliability","delivery delays/quality issues"]$json$::jsonb, $json${"summary":"Mixed: promotions positive, complaints on items/support; responsive on X/HelloPeter; no major backlash.","positive_themes":["quick delivery","convenience","fresh products","late-night availability","professional drivers"],"common_concerns":["high fees/surge pricing","late/wrong deliveries","app crashes/tracking issues","refund delays","expired/fake products"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
