:jsonb, $json$["convenience no waste","recipe variety","flexible plans","good CS resolution","ethical sourcing"]$json$::jsonb, $json$["premium pricing","inconsistent produce quality","app connectivity issues"]$json$::jsonb, $json${"summary":"Positive on Reddit/Trustpilot for convenience/recipes (3.8/5); concerns on cost/quality; improved CS.","positive_themes":["tasty recipes","fresh ingredients","time-saving","variety","flexibility"],"common_concerns":["high price","packaging waste","occasional poor produce/delayed delivery"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('yebo-fresh', 'Yebo Fresh', 'food-delivery', 72, 'GO WITH CAUTION', 'https://www.yebofresh.co.za/logo.png', 'https://www.yebofresh.co.za', $json$[{"category":"Compliance","score":"18/20","description":"No regulatory complaints, fines, or issues found. Operates legally as Smollan-acquired company partnering with major brands like MTN, Unilever."},{"category":"Customer Satisfaction","score":"10/20","description":"No HelloPeter/Google consumer reviews found. Employee satisfaction mixed at 3.1/5 on Indeed. Positive media coverage on growth/impact."},{"category":"Product Value","score":"28/30","description":"Optimized supply chain reduces costs for township retailers vs traditional wholesalers; bulk discounts passed on."},{"category":"Innovation","score":"9/10","description":"Tech platform with AI trends, real-time dashboards, geospatial mapping, WhatsApp B2B ordering tailored for townships. Field + digital hybrid model."},{"category":"Customer Support","score":"10/12","description":"Field agents (220), WhatsApp ordering/support, email. No specific response quality data; assumed adequate for B2B."},{"category":"Accessibility & Security","score":"8/10","description":"B2B platform with data encryption in app; no POPIA issues found; township accessibility via WhatsApp/web. Assumed standard security as Smollan subsidiary."}]$json$::jsonb, $json$["WhatsApp/web ordering","last-mile logistics to townships","field sales activation","real-time analytics","72k+ retailer network","Smollan-backed distribution"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: B2B wholesale; competitive bulk pricing (no public consumer rates)","features":""}]$json$::jsonb, $json${"google_play":"N/A (field app, no rating; 100+ downloads)","ios":"N/A (no app found)"}$json$::jsonb, $json$["Township market penetration","major brand partnerships (Unilever, MTN)","rapid scaling/growth","acquisition by Smollan","job creation"]$json$::jsonb, $json$["Scarce public feedback","B2C shift post-acquisition","niche B2B model"]$json$::jsonb, $json${"summary":"No HelloPeter/Google reviews found. Positive media on expansion/impact; no recent complaints on social/news.","positive_themes":["Inclusive growth","tech adoption in informal economy","efficient supply chain","community upliftment"],"common_concerns":["Limited public reviews","employee management complaints"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
